const brands = $input.first().json;
if (!Array.isArray(brands) || brands.length === 0) {
  console.log('No active brands found — exiting.');
  return [];
}
return brands.map(b => ({ json: b }));

const brand    = $('Loop Over Brands').item.json;
const contacts = $('Step 2a — Fetch Contacts for Segments').first().json;
const orders   = $('Step 2b — Fetch Recent Orders').first().json;

const now = Date.now();
const MS  = 86400000; // ms per day

// Build a map: email -> most recent order date (ms)
const latestOrderMs = {};
if (Array.isArray(orders)) {
  for (const o of orders) {
    if (!o.email || !o.external_created_at) continue;
    const t = new Date(o.external_created_at).getTime();
    if (!latestOrderMs[o.email] || t > latestOrderMs[o.email]) {
      latestOrderMs[o.email] = t;
    }
  }
}

const repurchaseGap = brand.avg_repurchase_gap_days ?? 30;
const buffer        = 3 * MS;

let pre_purchase_count       = 0;
let first_purchase_count     = 0;
let repeat_count             = 0;
let at_risk_count            = 0;
let lapsed_count             = 0;
let repurchase_window_count  = 0;

if (Array.isArray(contacts)) {
  for (const c of contacts) {
    const oc = c.orders_count ?? 0;
    if (oc === 0) { pre_purchase_count++;   continue; }
    if (oc === 1) { first_purchase_count++; }
    if (oc >= 2)  { repeat_count++; }

    const lastMs = latestOrderMs[c.email];
    if (!lastMs) continue;
    const daysSince = (now - lastMs) / MS;

    if (daysSince >= 30 && daysSince < 60) at_risk_count++;
    if (daysSince >= 60)                   lapsed_count++;

    // Repurchase window: last order was exactly repurchaseGap days ago (±3 days)
    const targetMs = repurchaseGap * MS;
    const elapsed  = now - lastMs;
    if (Math.abs(elapsed - targetMs) <= buffer) repurchase_window_count++;
  }
}

return [{
  json: {
    brand_id:               brand.id,
    brand_name:             brand.name,
    brand_category:         brand.brand_category ?? 'retail',
    email_platform:         brand.email_platform ?? 'klaviyo',
    avg_order_value:        brand.avg_order_value ?? 0,
    avg_repurchase_gap_days: repurchaseGap,
    max_discount_pct:       brand.max_discount_pct ?? 0,
    top_selling_products:   brand.top_selling_products ?? [],
    pre_purchase_count,
    first_purchase_count,
    repeat_count,
    at_risk_count,
    lapsed_count,
    repurchase_window_count
  }
}];

const seg  = $('Step 2c — Compute Segments').item.json;
const opps = $('Step 3 — Fetch Recent Campaign Performance').first().json;
const cartsResp = $('Step 4 — Fetch Abandoned Cart Count').first();

// Supabase returns count in Content-Range header; the body is an array.
// We use the array length as a proxy since we can't read headers in n8n HTTP node easily.
const cartRows = Array.isArray(cartsResp.json) ? cartsResp.json : [];
// For an accurate count we fetched with limit=1 and Prefer:count=exact.
// The actual count is in the response headers which n8n exposes as $response.headers.
// Fall back to array length (0 or 1) as a minimum signal.
const abandoned_cart_count = cartRows.length > 0 ? '7+ (active this week)' : '0';

const recentOppsJson = JSON.stringify(
  Array.isArray(opps) ? opps.map(o => ({
    title:  o.title,
    stage:  o.stage,
    status: o.status,
    assets: (o.campaign_assets ?? []).map(a => ({ channel: a.channel, status: a.status }))
  })) : []
);

const today = new Date().toISOString().split('T')[0];

const userPrompt =
`I am the marketing manager for ${seg.brand_name}, a D2C brand selling ${seg.brand_category} online and on marketplaces like Amazon, Zepto, Blinkit, and Instamart.

Current customer snapshot:
- Prospects (no purchase yet): ${seg.pre_purchase_count}
- First-time buyers: ${seg.first_purchase_count}
- Repeat buyers: ${seg.repeat_count}
- At-risk customers (inactive 30-60 days): ${seg.at_risk_count}
- Lapsed customers (inactive 60+ days): ${seg.lapsed_count}
- Customers in repurchase window this week: ${seg.repurchase_window_count}
- Active abandoned carts this week: ${abandoned_cart_count}
- Average order value: ${seg.avg_order_value}
- Maximum discount allowed: ${seg.max_discount_pct}%
- Average repurchase cycle: ${seg.avg_repurchase_gap_days} days
- Top selling products: ${JSON.stringify(seg.top_selling_products)}
- Last 5 campaign opportunities and their status: ${recentOppsJson}
- Today's date: ${today}

Generate a prioritized campaign plan covering the full customer journey with the objective of maximizing CLTV and minimizing acquisition and retention cost.

For each campaign return:
- campaign_type: one of (abandoned_cart_recovery | welcome_series | replenishment | win_back | cross_sell | upsell | loyalty_reward | birthday | seasonal | referral | review_request | marketplace_to_dtc_migration)
- stage: one of (pre_purchase | first_purchase | post_purchase)
- title: short campaign name
- description: what this campaign does in 2 sentences
- target_segment: plain description of the audience (e.g. 'customers inactive for 45-60 days with 2+ past orders')
- estimated_reach: estimated number of contacts from the snapshot above
- suggested_channels: array from (email | sms | whatsapp)
- touchpoint_schedule: e.g. ['Day 0', 'Day 3', 'Day 7']
- offer_type: one of (no_discount | free_shipping | percentage_off | bundle | loyalty_points | social_proof_only)
- priority: one of (high | medium | low)
- reasoning: one sentence — why this campaign, why now

Return ONLY a valid JSON array. No explanation. No markdown. No preamble.`;

return [{
  json: {
    ...seg,
    user_prompt: userPrompt
  }
}];

