const ctx      = $('Build Claude Prompt').item.json;
const response = $input.first().json;

let campaigns;
try {
  const rawText = response.content?.[0]?.text ?? '[]';
  const cleaned = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  campaigns = JSON.parse(cleaned);
  if (!Array.isArray(campaigns)) throw new Error('Claude did not return an array');
} catch (e) {
  throw new Error(`Failed to parse Claude campaign plan: ${e.message}`);
}

// Emit one item per campaign, carrying brand context forward
return campaigns.map(c => ({
  json: {
    brand_id:          ctx.brand_id,
    brand_name:        ctx.brand_name,
    stage:             c.stage,
    title:             c.title,
    description:       c.description,
    target_segment:    c.target_segment,
    estimated_reach:   typeof c.estimated_reach === 'number' ? c.estimated_reach : 0,
    suggested_channels: Array.isArray(c.suggested_channels) ? c.suggested_channels : [],
    priority:          c.priority ?? 'medium',
    reasoning:         c.reasoning ?? '',
    // Extra fields stored in reasoning for downstream use
    campaign_type:     c.campaign_type ?? null,
    touchpoint_schedule: c.touchpoint_schedule ?? [],
    offer_type:        c.offer_type ?? 'no_discount'
  }
}));

// Collect all saved opportunity rows across all items in this batch
const allItems = $input.all();
const brandId   = allItems[0]?.json?.brand_id ?? $('Build Claude Prompt').item.json.brand_id;
const brandName = $('Build Claude Prompt').item.json.brand_name;

const saved = allItems
  .map(i => (Array.isArray(i.json) ? i.json[0] : i.json))
  .filter(r => r?.id);

return [{
  json: {
    brand_id:            brandId,
    brand_name:          brandName,
    opportunities_count: saved.length,
    opportunity_ids:     saved.map(r => r.id),
    generated_at:        new Date().toISOString()
  }
}];
